+import type { AnyColumn } from '~/column.ts';
+import type { SQL, SQLWrapper } from '../sql.ts';
+import { sql } from '../sql.ts';
+
+type WindowValue<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TData> ? TData : unknown;
+type WindowOrder = SQLWrapper;
+
+export interface WindowSpec {
+	partitionBy?: WindowOrder | WindowOrder[];
+	orderBy?: WindowOrder | WindowOrder[];
+	frame?: WindowFrame;
+}
+
+export interface WindowFrame {
+	type: 'rows' | 'range';
+	from: WindowBoundary;
+	to: WindowBoundary;
+}
+
+export interface WindowBoundary {
+	readonly kind: 'unbounded preceding' | 'preceding' | 'current row' | 'following' | 'unbounded following';
+	readonly offset?: number;
+}
+
+export const unboundedPreceding: WindowBoundary = { kind: 'unbounded preceding' };
+export const currentRow: WindowBoundary = { kind: 'current row' };
+export const unboundedFollowing: WindowBoundary = { kind: 'unbounded following' };
+
+function offsetBoundary(kind: 'preceding' | 'following', offset: number): WindowBoundary {
+	if (!Number.isInteger(offset) || offset < 0) {
+		throw new Error(`${kind}() requires a non-negative integer, received ${offset}`);
+	}
+	return { kind, offset };
+}
+
+export function preceding(offset: number): WindowBoundary {
+	return offsetBoundary('preceding', offset);
+}
+
+export function following(offset: number): WindowBoundary {
+	return offsetBoundary('following', offset);
+}
+
+function boundaryPosition(boundary: WindowBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return -Infinity;
+		case 'preceding': return -boundary.offset!;
+		case 'current row': return 0;
+		case 'following': return boundary.offset!;
+		case 'unbounded following': return Infinity;
+	}
+}
+
+function frame(type: WindowFrame['type'], spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to"');
+	}
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return frame('range', spec);
+}
+
+function buildBoundary(boundary: WindowBoundary): SQL {
+	return boundary.offset === undefined ? sql.raw(boundary.kind) : sql`${sql.raw(String(boundary.offset))} ${sql.raw(boundary.kind)}`;
+}
+
+export function buildWindow(spec: WindowSpec): SQL {
+	const partitionBy = spec.partitionBy === undefined ? [] : Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
+	const orderBy = spec.orderBy === undefined ? [] : Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
+	const partitionBySql = partitionBy.length ? sql`partition by ${sql.join(partitionBy, sql`, `)}` : undefined;
+	const orderBySql = orderBy.length ? sql`order by ${sql.join(orderBy, sql`, `)}` : undefined;
+	const frameSql = spec.frame
+		? sql`${sql.raw(spec.frame.type)} between ${buildBoundary(spec.frame.from)} and ${buildBoundary(spec.frame.to)}`
+		: undefined;
+	return sql.join([partitionBySql, orderBySql, frameSql].filter((part): part is SQL => part !== undefined), sql` `);
+}
+
+class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec): SQL<T>;
+	over(name: string): SQL<T>;
+	over(specOrName: WindowSpec | string): SQL<T> {
+		return typeof specOrName === 'string'
+			? sql`${this.expression} over ${sql.identifier(specOrName)}`
+			: sql`${this.expression} over (${buildWindow(specOrName)})`;
+	}
+
+	getSQL(): SQL<T> {
+		return this.expression;
+	}
+}
+
+function windowFunction<T>(name: string, args: (SQLWrapper | number | undefined)[]): WindowFunction<T> {
+	const values = args.filter((arg): arg is SQLWrapper | number => arg !== undefined).map((arg) =>
+		typeof arg === 'number' ? sql.raw(String(arg)) : arg
+	);
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(values, sql`, `)})`);
+}
+
+function positiveInteger(functionName: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${functionName}() requires a positive integer, received ${value}`);
+	}
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number', []); }
+export function rank(): WindowFunction<number> { return windowFunction('rank', []); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank', []); }
+export function ntile(buckets: number): WindowFunction<number> { positiveInteger('ntile', buckets); return windowFunction('ntile', [buckets]); }
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank', []); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist', []); }
+
+export function lag<T extends SQLWrapper>(value: T): WindowFunction<WindowValue<T> | null>;
+export function lag<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<Exclude<WindowValue<T>, null>>;
+export function lag<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<WindowValue<T> | null> { return windowFunction('lag', [value, offset, defaultValue]); }
+export function lead<T extends SQLWrapper>(value: T): WindowFunction<WindowValue<T> | null>;
+export function lead<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<Exclude<WindowValue<T>, null>>;
+export function lead<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<WindowValue<T> | null> { return windowFunction('lead', [value, offset, defaultValue]); }
+export function firstValue<T extends SQLWrapper>(value: T): WindowFunction<WindowValue<T> | null> { return windowFunction('first_value', [value]); }
+export function lastValue<T extends SQLWrapper>(value: T): WindowFunction<WindowValue<T> | null> { return windowFunction('last_value', [value]); }
+export function nthValue<T extends SQLWrapper>(value: T, nth: number): WindowFunction<WindowValue<T> | null> { positiveInteger('nthValue', nth); return windowFunction('nth_value', [value, nth]); }
+
+export function windowSum(value: SQLWrapper): WindowFunction<string | null> { return windowFunction('sum', [value]); }
+export function windowAvg(value: SQLWrapper): WindowFunction<string | null> { return windowFunction('avg', [value]); }
+export function windowMin<T extends SQLWrapper>(value: T): WindowFunction<WindowValue<T> | null> { return windowFunction('min', [value]); }
+export function windowMax<T extends SQLWrapper>(value: T): WindowFunction<WindowValue<T> | null> { return windowFunction('max', [value]); }
+export function windowCount(value?: SQLWrapper): WindowFunction<number> { return windowFunction('count', value === undefined ? [sql.raw('*')] : [value]); }
