+import { expect, test } from 'vitest';
+
+import { PgDialect, pgTable, serial } from '~/pg-core';
+import { PgSelectBuilder } from '~/pg-core/query-builders/select';
+import {
+	cumeDist,
+	currentRow,
+	denseRank,
+	following,
+	firstValue,
+	lag,
+	lastValue,
+	lead,
+	nthValue,
+	ntile,
+	percentRank,
+	range,
+	rank,
+	rowNumber,
+	rows,
+	unboundedPreceding,
+	windowAvg,
+	windowCount,
+	windowMax,
+	windowMin,
+	windowSum,
+} from '~/sql';
+
+const users = pgTable('users', { id: serial().primaryKey(), score: serial() });
+const dialect = new PgDialect();
+
+test('window functions render snake_case names and inline positional arguments', () => {
+	const spec = { partitionBy: users.id, orderBy: users.score, frame: rows({ from: unboundedPreceding, to: currentRow }) };
+	const query = dialect.sqlToQuery(
+		new PgSelectBuilder({
+			fields: {
+				row: rowNumber().over(spec), rank: rank().over(spec), dense: denseRank().over(spec), tiles: ntile(2).over(spec),
+				percent: percentRank().over(spec), cumulative: cumeDist().over(spec), previous: lag(users.score, 0).over(spec),
+				next: lead(users.score, 1, users.score).over(spec), first: firstValue(users.score).over(spec),
+				last: lastValue(users.score).over(spec), nth: nthValue(users.score, 2).over(spec), sum: windowSum(users.score).over(spec),
+				avg: windowAvg(users.score).over(spec), min: windowMin(users.score).over(spec), max: windowMax(users.score).over(spec), count: windowCount().over(spec),
+			},
+			session: undefined,
+			dialect,
+		}).from(users).getSQL(),
+	);
+	expect(query.params).toEqual([]);
+	expect(query.sql).toContain('row_number() over');
+	expect(query.sql).toContain('dense_rank() over');
+	expect(query.sql).toContain('percent_rank() over');
+	expect(query.sql).toContain('cume_dist() over');
+	expect(query.sql).toContain('ntile(2) over');
+	expect(query.sql).toContain('lag("users"."score", 0) over');
+	expect(query.sql).toContain('count(*) over');
+});
+
+test('window definitions and empty over specifications compile correctly', () => {
+	const query = dialect.sqlToQuery(
+		new PgSelectBuilder({ fields: { row: rowNumber().over({}) }, session: undefined, dialect })
+			.from(users)
+			.window('by_score', { orderBy: users.score, frame: range({ from: currentRow, to: following(1) }) })
+			.orderBy(users.id)
+			.getSQL(),
+	);
+	expect(query.sql).toContain('row_number() over ()');
+	expect(query.sql).toContain(' window "by_score" as (order by "users"."score" range between current row and 1 following) order by');
+});
+
+test('window validation rejects invalid arguments and names', () => {
+	expect(() => ntile(0)).toThrow('ntile');
+	expect(() => nthValue(users.id, -1)).toThrow('nthValue');
+	expect(() => rows({ from: currentRow, to: unboundedPreceding })).toThrow('from');
+	expect(() => following(-1)).toThrow('following');
+	const builder = new PgSelectBuilder({ fields: {}, session: undefined, dialect }).from(users);
